import { z } from "zod";

export const registrationSchema = z.object({
  username: z.string().min(3, "Username deve contenere almeno 3 caratteri"),
  email: z.string().email("Email non valida"),
  role: z.enum(["user", "admin", "contributor"]),
  otherInfo: z.string().optional(),
  newsletter: z.boolean().optional(),
  frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
  bio: z.string().optional(),
})
  .superRefine((data, context) => {
    // otherInfo is required when role === "contributor"
    if (
      data.role === "contributor" &&
      !data.otherInfo &&
      !context.errors["otherInfo"]
    ) {
      context.addIssue({
        code: z.ZodIssueCode.custom,
        path: ["otherInfo"],
        message: "otherInfo è obbligatorio per contributori",
      });
    }

    // frequency is required when newsletter === true
    if (
      data.newsletter &&
      data.newsletter === true &&
      !data.frequency &&
      !context.errors["frequency"]
    ) {
      context.addIssue({
        code: z.ZodIssueCode.custom,
        path: ["frequency"],
        message: "frequency è obbligatorio quando newsletter è stato selezionato",
      });
    }
  });

export type RegistrationFormValues = z.infer<typeof registrationSchema>;

export type RegistrationFormData = RegistrationFormValues;

